{
  "name": "TravelCrew AI",
  "description": "An AI-powered hotel booking platform for India featuring a multi-agent crew that researches, compares, and finds your perfect stay through natural language.",
  "requestFramePermissions": ["geolocation"]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Hotel {
  id: string;
  name: string;
  rating: number;
  location: string;
  pricePerNight: number;
  totalPrice: number;
  image: string;
  description: string;
  whyPerfect: string[];
  aiAnalysis: {
    positive: string[];
    concerns: string[];
  };
  inclusions: string[];
  comparisons: {
    platform: string;
    price: number;
    isBest?: boolean;
  }[];
  tag?: string; // e.g., "BEST MATCH", "BUDGET OPTION"
}

export interface SearchIntent {
  destination: string;
  checkIn: string;
  checkOut: string;
  adults: number;
  children: number;
  budgetMax: number;
  requirements: string[];
}

export interface AgentLog {
  agent: string;
  status: 'pending' | 'working' | 'completed';
  message: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: string;
}

export enum AppState {
  LANDING = 'landing',
  SEARCHING = 'searching',
  RESULTS = 'results'
}

export const INDIA_DEFAULTS = {
  country: 'India',
  currency: 'INR',
  currencySymbol: '₹',
  timezone: 'Asia/Kolkata',
  language: 'en-IN',
  popularCities: [
    'Mumbai', 'Delhi', 'Bangalore', 'Hyderabad', 'Chennai',
    'Kolkata', 'Pune', 'Ahmedabad', 'Jaipur', 'Goa'
  ],
  internationalDestinations: [
    'Dubai', 'Singapore', 'Bangkok', 'Bali', 'Maldives',
    'Malaysia', 'Sri Lanka', 'Nepal', 'London', 'USA'
  ]
};

export const TRENDING_SEARCHES = [
  { label: 'Weekend getaway in Goa', budget: '₹3k-5k', query: 'Find me a 2-night stay in North Goa near the beach for 2 adults under ₹5000/night' },
  { label: 'Business stay in Bangalore', budget: '₹4k-6k', query: 'I need a business hotel in Whitefield, Bangalore with fast WiFi and gym, budget ₹6000' },
  { label: 'Family trip to Jaipur', budget: '₹5k-8k', query: 'Family vacation in Jaipur for 4 people, must have pool and vegetarian food' },
  { label: 'Honeymoon in Maldives', budget: '₹15k-25k', query: 'Romantic honeymoon resort in Maldives with private beach and all inclusive meals' }
];

export const INDIAN_PREFERENCES = {
  commonRequirements: [
    'Vegetarian food options',
    'Jain food available',
    'Family rooms (3-4 people)',
    'Close to railway station/airport',
    'Free WiFi (mandatory)',
    'Parking available',
    'Early check-in flexibility'
  ]
};

import { GoogleGenAI, Type } from "@google/genai";
import { Hotel, SearchIntent } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const HOTEL_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    intent: {
      type: Type.OBJECT,
      properties: {
        destination: { type: Type.STRING },
        checkIn: { type: Type.STRING },
        checkOut: { type: Type.STRING },
        adults: { type: Type.NUMBER },
        children: { type: Type.NUMBER },
        budgetMax: { type: Type.NUMBER },
        requirements: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    },
    hotels: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          name: { type: Type.STRING },
          rating: { type: Type.NUMBER },
          location: { type: Type.STRING },
          pricePerNight: { type: Type.NUMBER },
          totalPrice: { type: Type.NUMBER },
          image: { type: Type.STRING },
          description: { type: Type.STRING },
          whyPerfect: { type: Type.ARRAY, items: { type: Type.STRING } },
          aiAnalysis: {
            type: Type.OBJECT,
            properties: {
              positive: { type: Type.ARRAY, items: { type: Type.STRING } },
              concerns: { type: Type.ARRAY, items: { type: Type.STRING } }
            }
          },
          inclusions: { type: Type.ARRAY, items: { type: Type.STRING } },
          comparisons: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                platform: { type: Type.STRING },
                price: { type: Type.NUMBER },
                isBest: { type: Type.BOOLEAN }
              }
            }
          },
          tag: { type: Type.STRING }
        }
      }
    },
    agentLogs: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          agent: { type: Type.STRING },
          message: { type: Type.STRING }
        }
      }
    }
  }
};

export async function searchHotels(userInput: string) {
  const prompt = `
    You are the manager of TravelCrew AI, an Indian hotel booking platform. 
    Analyze the user's natural language request: "${userInput}".

    1. Act as "Research Agent": Find 3-5 realistic hotels in the requested location.
    2. Act as "Review Analyst": Generate detailed pros/cons based on typical Indian traveler reviews.
    3. Act as "Price Agent": Create a price comparison across platforms like MakeMyTrip, Booking.com, and Direct.
    4. Act as "Amenity Checker": Verify if they meet specific Indian requirements (Veg food, Family rooms, etc.).

    Output exactly 3 top recommendations. 
    One should be tagged "BEST MATCH", one "BUDGET CHOICE", and one "PREMIUM UPGRADE".
    Use Indian Rupee (INR) values. 
    Current year is 2024. If dates aren't specified, assume a 2-night stay next weekend.

    IMPORTANT: Provide realistic-sounding hotel names for the destination, even if hypothetical.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: HOTEL_SCHEMA,
        thinkingConfig: { thinkingBudget: 2000 }
      },
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini Search Error:", error);
    throw error;
  }
}

import React from 'react';
import { AgentLog } from '../types';

interface AgentStatusPanelProps {
  logs: AgentLog[];
}

const AgentStatusPanel: React.FC<AgentStatusPanelProps> = ({ logs }) => {
  return (
    <div className="bg-white border rounded-xl p-6 shadow-sm mb-8">
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-sm font-semibold uppercase tracking-wider text-slate-500">
          🤖 AI Crew Working...
        </h3>
        <span className="text-xs font-medium text-blue-600 bg-blue-50 px-2 py-1 rounded-full">
          {logs.filter(l => l.status === 'completed').length}/5 Agents Done
        </span>
      </div>

      <div className="space-y-4">
        {logs.map((log, idx) => (
          <div key={idx} className="flex items-start gap-3">
            <div className={`mt-1 h-5 w-5 rounded-full flex items-center justify-center text-xs
              ${log.status === 'completed' ? 'bg-green-100 text-green-600' : 
                log.status === 'working' ? 'bg-blue-100 text-blue-600 agent-pulse' : 'bg-slate-100 text-slate-400'}`}>
              {log.status === 'completed' ? '✓' : log.status === 'working' ? '●' : '○'}
            </div>
            <div>
              <p className="text-sm font-semibold text-slate-800">{log.agent}</p>
              <p className="text-xs text-slate-500">{log.message}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="mt-6 h-1 w-full bg-slate-100 rounded-full overflow-hidden">
        <div 
          className="h-full bg-blue-500 transition-all duration-500"
          style={{ width: `${(logs.filter(l => l.status === 'completed').length / logs.length) * 100}%` }}
        />
      </div>
    </div>
  );
};

export default AgentStatusPanel;

import React from 'react';
import { Hotel } from '../types';
import { INDIA_DEFAULTS } from '../constants';

interface HotelCardProps {
  hotel: Hotel;
  onBook: (hotel: Hotel) => void;
}

const HotelCard: React.FC<HotelCardProps> = ({ hotel, onBook }) => {
  const isBest = hotel.tag === "BEST MATCH";

  return (
    <div className={`bg-white rounded-2xl overflow-hidden border-2 transition-all hover:shadow-xl ${isBest ? 'border-blue-500 ring-4 ring-blue-50' : 'border-slate-100'}`}>
      {hotel.tag && (
        <div className={`px-4 py-1.5 text-xs font-bold uppercase tracking-widest text-white text-center
          ${isBest ? 'bg-blue-500' : hotel.tag.includes('BUDGET') ? 'bg-green-500' : 'bg-purple-500'}`}>
          {hotel.tag}
        </div>
      )}

      <div className="md:flex">
        <div className="md:w-1/3 relative">
          <img 
            src={hotel.image} 
            alt={hotel.name}
            className="h-64 md:h-full w-full object-cover"
          />
          <div className="absolute top-4 left-4 bg-white/90 backdrop-blur-sm px-2 py-1 rounded text-xs font-bold shadow-sm">
            ⭐ {hotel.rating}/5
          </div>
        </div>

        <div className="md:w-2/3 p-6 flex flex-col">
          <div className="flex justify-between items-start mb-2">
            <div>
              <h3 className="text-xl font-bold text-slate-900">{hotel.name}</h3>
              <p className="text-sm text-slate-500 flex items-center gap-1">
                📍 {hotel.location}
              </p>
            </div>
            <div className="text-right">
              <p className="text-2xl font-extrabold text-slate-900">{INDIA_DEFAULTS.currencySymbol}{hotel.pricePerNight.toLocaleString('en-IN')}</p>
              <p className="text-xs text-slate-500">per night • Total: {INDIA_DEFAULTS.currencySymbol}{hotel.totalPrice.toLocaleString('en-IN')}</p>
            </div>
          </div>

          <div className="mb-4">
            <h4 className="text-xs font-bold uppercase text-slate-400 mb-2">Why this is perfect for you</h4>
            <div className="flex flex-wrap gap-2">
              {hotel.whyPerfect.map((reason, i) => (
                <span key={i} className="bg-blue-50 text-blue-700 px-3 py-1 rounded-full text-xs font-medium border border-blue-100">
                  {reason}
                </span>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
            <div className="bg-slate-50 p-4 rounded-xl">
              <h4 className="text-xs font-bold uppercase text-slate-500 mb-2 flex items-center gap-1">
                ✨ Positive Reviews (AI Summary)
              </h4>
              <ul className="space-y-1">
                {hotel.aiAnalysis.positive.map((p, i) => (
                  <li key={i} className="text-xs text-slate-600 flex items-start gap-1">
                    <span className="text-green-500">•</span> {p}
                  </li>
                ))}
              </ul>
            </div>
            <div className="bg-orange-50/50 p-4 rounded-xl">
              <h4 className="text-xs font-bold uppercase text-orange-600 mb-2 flex items-center gap-1">
                ⚠️ Areas to Note
              </h4>
              <ul className="space-y-1">
                {hotel.aiAnalysis.concerns.map((c, i) => (
                  <li key={i} className="text-xs text-slate-600 flex items-start gap-1">
                    <span className="text-orange-400">•</span> {c}
                  </li>
                ))}
              </ul>
            </div>
          </div>

          <div className="mt-auto pt-6 border-t flex flex-col sm:flex-row items-center justify-between gap-4">
            <div className="flex flex-col gap-1">
              <p className="text-xs font-bold text-slate-400 uppercase">Best Price Comparison</p>
              <div className="flex gap-4">
                {hotel.comparisons.map((comp, i) => (
                  <div key={i} className="flex flex-col">
                    <span className="text-[10px] text-slate-500">{comp.platform}</span>
                    <span className={`text-xs font-bold ${comp.isBest ? 'text-green-600' : 'text-slate-600'}`}>
                      {INDIA_DEFAULTS.currencySymbol}{comp.price.toLocaleString('en-IN')}
                    </span>
                  </div>
                ))}
              </div>
            </div>
            <button 
              onClick={() => onBook(hotel)}
              className="w-full sm:w-auto bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-8 rounded-xl transition-all shadow-lg shadow-blue-200"
            >
              Book Now
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default HotelCard;

import React, { useState, useRef, useEffect } from 'react';
import Header from './components/Header';
import AgentStatusPanel from './components/AgentStatusPanel';
import HotelCard from './components/HotelCard';
import { AppState, Hotel, AgentLog, ChatMessage } from './types';
import { INDIA_DEFAULTS, TRENDING_SEARCHES } from './constants';
import { searchHotels } from './services/geminiService';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.LANDING);
  const [query, setQuery] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [agentLogs, setAgentLogs] = useState<AgentLog[]>([
    { agent: 'Research Specialist', status: 'pending', message: 'Searching multiple platforms...' },
    { agent: 'Review Analyst', status: 'pending', message: 'Analyzing sentiment from 1000s of reviews...' },
    { agent: 'Price Specialist', status: 'pending', message: 'Comparing rates across 8+ sources...' },
    { agent: 'Amenity Checker', status: 'pending', message: 'Verifying facilities & dietary options...' },
    { agent: 'Booking Coordinator', status: 'pending', message: 'Ready for final confirmation...' }
  ]);
  const [results, setResults] = useState<Hotel[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, agentLogs]);

  const handleSearch = async (customQuery?: string) => {
    const activeQuery = customQuery || query;
    if (!activeQuery.trim()) return;

    setAppState(AppState.SEARCHING);
    setIsLoading(true);
    setMessages([{ 
      id: Date.now().toString(), 
      role: 'user', 
      content: activeQuery, 
      timestamp: new Date().toLocaleTimeString() 
    }]);

    // Reset Logs
    setAgentLogs(prev => prev.map(l => ({ ...l, status: 'pending' })));

    try {
      // Simulate Agent Steps for UI
      const steps = [0, 1, 2, 3];
      for (const step of steps) {
        setAgentLogs(prev => {
          const newLogs = [...prev];
          if (step > 0) newLogs[step - 1].status = 'completed';
          newLogs[step].status = 'working';
          return newLogs;
        });
        await new Promise(r => setTimeout(r, 1500));
      }

      const response = await searchHotels(activeQuery);

      setAgentLogs(prev => prev.map(l => ({ ...l, status: 'completed' })));
      setResults(response.hotels);
      setAppState(AppState.RESULTS);
    } catch (error) {
      console.error(error);
      alert("Something went wrong with the AI search. Please try again.");
      setAppState(AppState.LANDING);
    } finally {
      setIsLoading(false);
    }
  };

  const handleBook = (hotel: Hotel) => {
    alert(`Redirecting to payment gateway for ${hotel.name}. Total: ${INDIA_DEFAULTS.currencySymbol}${hotel.totalPrice.toLocaleString('en-IN')}`);
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header onLogoClick={() => setAppState(AppState.LANDING)} />

      <main className="flex-1 w-full max-w-5xl mx-auto px-4 py-8 md:py-12">
        {appState === AppState.LANDING && (
          <div className="flex flex-col items-center justify-center text-center space-y-12 py-10">
            <div className="space-y-4 max-w-3xl">
              <h1 className="text-4xl md:text-6xl font-extrabold text-slate-900 leading-tight">
                Your Personal AI <span className="text-blue-600">Travel Crew</span>
              </h1>
              <p className="text-lg md:text-xl text-slate-600">
                Stop searching. Start traveling. Tell our AI agents what you need and we'll handle the research, comparison, and booking.
              </p>
            </div>

            <div className="w-full max-w-3xl bg-white p-2 rounded-2xl shadow-2xl border border-slate-200">
              <div className="flex flex-col sm:flex-row gap-2">
                <input 
                  type="text" 
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
                  placeholder='e.g., "Find a family hotel in Goa under ₹5000 with pool and veg food"'
                  className="flex-1 px-6 py-4 rounded-xl text-lg outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                />
                <button 
                  onClick={() => handleSearch()}
                  className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 px-8 rounded-xl transition-all flex items-center justify-center gap-2 shadow-lg shadow-blue-200"
                >
                  <span>Find My Perfect Stay</span>
                  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-5 h-5">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
                  </svg>
                </button>
              </div>
            </div>

            <div className="w-full max-w-3xl grid grid-cols-1 md:grid-cols-2 gap-4 text-left">
              <h3 className="col-span-full text-sm font-bold uppercase tracking-widest text-slate-400 mb-2">🌟 Trending Searches</h3>
              {TRENDING_SEARCHES.map((item, idx) => (
                <button 
                  key={idx}
                  onClick={() => handleSearch(item.query)}
                  className="p-4 bg-white rounded-xl border border-slate-200 hover:border-blue-400 hover:shadow-md transition-all group flex items-center justify-between"
                >
                  <div className="flex flex-col">
                    <span className="font-semibold text-slate-800 group-hover:text-blue-600 transition-colors">{item.label}</span>
                    <span className="text-xs text-slate-500">{item.budget}</span>
                  </div>
                  <div className="h-8 w-8 rounded-full bg-slate-50 flex items-center justify-center text-slate-400 group-hover:bg-blue-50 group-hover:text-blue-500 transition-all">
                    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                      <path strokeLinecap="round" strokeLinejoin="round" d="M12 4.5v15m7.5-7.5h-15" />
                    </svg>
                  </div>
                </button>
              ))}
            </div>

            <section className="grid grid-cols-1 md:grid-cols-3 gap-8 pt-12 text-center">
              <div className="space-y-3">
                <div className="h-12 w-12 bg-blue-100 text-blue-600 rounded-2xl mx-auto flex items-center justify-center font-bold text-xl">1</div>
                <h4 className="font-bold text-slate-900">Tell Us Your Needs</h4>
                <p className="text-sm text-slate-500">Describe your ideal stay in plain English. No filters required.</p>
              </div>
              <div className="space-y-3">
                <div className="h-12 w-12 bg-blue-100 text-blue-600 rounded-2xl mx-auto flex items-center justify-center font-bold text-xl">2</div>
                <h4 className="font-bold text-slate-900">AI Crew Researches</h4>
                <p className="text-sm text-slate-500">5 specialized agents work together to analyze thousands of options.</p>
              </div>
              <div className="space-y-3">
                <div className="h-12 w-12 bg-blue-100 text-blue-600 rounded-2xl mx-auto flex items-center justify-center font-bold text-xl">3</div>
                <h4 className="font-bold text-slate-900">Book Instantly</h4>
                <p className="text-sm text-slate-500">Get top 3 curated matches and pay securely via UPI or cards.</p>
              </div>
            </section>
          </div>
        )}

        {(appState === AppState.SEARCHING || appState === AppState.RESULTS) && (
          <div className="flex flex-col gap-8 pb-20">
            <div className="flex items-center justify-between border-b pb-6">
              <button 
                onClick={() => setAppState(AppState.LANDING)}
                className="flex items-center gap-2 text-slate-500 hover:text-slate-900 font-semibold"
              >
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-5 h-5">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 19.5L8.25 12l7.5-7.5" />
                </svg>
                Back to Search
              </button>
              <h2 className="text-xl font-extrabold text-slate-900">Finding Your Perfect Stay</h2>
              <div className="flex items-center gap-2">
                <div className="h-8 w-8 bg-slate-200 rounded-full"></div>
                <span className="text-xs font-bold text-slate-400">Personalizing Results...</span>
              </div>
            </div>

            <div className="flex flex-col gap-6">
              {messages.map(msg => (
                <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-xl p-4 rounded-2xl ${msg.role === 'user' ? 'bg-blue-600 text-white rounded-tr-none shadow-lg' : 'bg-white border rounded-tl-none shadow-sm text-slate-800'}`}>
                    <p className="text-sm leading-relaxed">{msg.content}</p>
                    <span className={`text-[10px] mt-2 block opacity-60 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                      {msg.timestamp}
                    </span>
                  </div>
                </div>
              ))}
            </div>

            <AgentStatusPanel logs={agentLogs} />

            {appState === AppState.RESULTS && (
              <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-1000">
                <div className="text-center space-y-2">
                  <h3 className="text-3xl font-extrabold text-slate-900">🎉 Found Your Perfect Matches!</h3>
                  <p className="text-slate-500">Our AI crew analyzed 40+ hotels to find these top picks for you.</p>
                </div>

                <div className="grid grid-cols-1 gap-8">
                  {results.map((hotel) => (
                    <HotelCard key={hotel.id} hotel={hotel} onBook={handleBook} />
                  ))}
                </div>

                <div className="bg-blue-50 border border-blue-100 p-8 rounded-2xl flex flex-col items-center text-center gap-6">
                  <div className="h-16 w-16 bg-white rounded-full flex items-center justify-center text-blue-600 shadow-sm border border-blue-100">
                    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-8 h-8">
                      <path strokeLinecap="round" strokeLinejoin="round" d="M9.879 7.519c1.171-1.025 3.071-1.025 4.242 0 1.172 1.025 1.172 2.687 0 3.712-.203.179-.43.326-.67.442-.745.361-1.45.999-1.45 1.827v.75M21 12a9 9 0 11-18 0 9 9 0 0118 0zm-9 5.25h.008v.008H12v-.008z" />
                    </svg>
                  </div>
                  <div className="space-y-2">
                    <h4 className="text-xl font-bold text-slate-900">Need help deciding?</h4>
                    <p className="text-slate-600 max-w-lg">Our AI can compare specific features, check for early check-in availability, or find alternative locations near these hotels.</p>
                  </div>
                  <div className="flex flex-wrap justify-center gap-3">
                    <button className="bg-white hover:bg-slate-50 text-slate-900 font-bold py-3 px-6 rounded-xl border transition-all text-sm shadow-sm">
                      Ask about breakfast options
                    </button>
                    <button className="bg-white hover:bg-slate-50 text-slate-900 font-bold py-3 px-6 rounded-xl border transition-all text-sm shadow-sm">
                      Compare family room sizes
                    </button>
                    <button className="bg-white hover:bg-slate-50 text-slate-900 font-bold py-3 px-6 rounded-xl border transition-all text-sm shadow-sm">
                      Check distance to airport
