import React, { useState } from 'react';
import { Hotel } from '../types';
import { INDIA_DEFAULTS } from '../constants';

interface BookingModalProps {
  hotel: Hotel;
  onClose: () => void;
  onComplete: () => void;
}

const BookingModal: React.FC<BookingModalProps> = ({ hotel, onClose, onComplete }) => {
  const [step, setStep] = useState<'details' | 'payment' | 'processing' | 'success' | 'failure'>('details');
  const [paymentMethod, setPaymentMethod] = useState('upi');
  const [errorMessage, setErrorMessage] = useState('');

  const handlePayment = () => {
    setStep('processing');
    setErrorMessage('');

    // Simulate network delay and potential failure
    setTimeout(() => {
      // Simulate an 80% success rate
      const isSuccessful = Math.random() > 0.2;

      if (isSuccessful) {
        setStep('success');
      } else {
        const errors = [
          "Transaction declined by your bank. Please check your balance or limit.",
          "Payment gateway is temporarily unreachable. Please try again.",
          "UPI ID verification failed. Please try a different method.",
          "The session has timed out. Please restart the payment process."
        ];
        setErrorMessage(errors[Math.floor(Math.random() * errors.length)]);
        setStep('failure');
      }
    }, 2500);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
      <div className="bg-white w-full max-w-lg rounded-3xl overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200">

        {step === 'details' && (
          <div className="p-8">
            <div className="flex justify-between items-start mb-6">
              <h2 className="text-2xl font-bold text-slate-900">Review Booking</h2>
              <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-6 h-6">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>

            <div className="flex gap-4 mb-6 p-4 bg-slate-50 rounded-2xl border border-slate-100">
              <img src={hotel.image} className="w-20 h-20 rounded-xl object-cover" />
              <div>
                <h4 className="font-bold text-slate-900">{hotel.name}</h4>
                <p className="text-sm text-slate-500">{hotel.location}</p>
                <div className="mt-1 text-blue-600 font-bold text-sm">₹{hotel.pricePerNight.toLocaleString('en-IN')} / night</div>
              </div>
            </div>

            <div className="space-y-4 mb-8">
              <div className="flex justify-between text-sm">
                <span className="text-slate-500">Duration</span>
                <span className="font-semibold">2 Nights</span>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-slate-500">Guests</span>
                <span className="font-semibold">2 Adults, 0 Children</span>
              </div>
              <div className="flex justify-between text-sm border-t pt-4">
                <span className="text-slate-900 font-bold">Total Payable</span>
                <span className="text-xl font-extrabold text-blue-600">₹{hotel.totalPrice.toLocaleString('en-IN')}</span>
              </div>
            </div>

            <button 
              onClick={() => setStep('payment')}
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-2xl shadow-lg transition-all"
            >
              Proceed to Payment
            </button>
          </div>
        )}

        {step === 'payment' && (
          <div className="p-8">
            <div className="flex items-center gap-4 mb-6">
              <button onClick={() => setStep('details')} className="p-2 hover:bg-slate-100 rounded-full">
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-5 h-5">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 19.5L8.25 12l7.5-7.5" />
                </svg>
              </button>
              <h2 className="text-xl font-bold text-slate-900">Choose Payment Method</h2>
            </div>

            <div className="space-y-3 mb-8">
              {[
                { id: 'upi', name: 'UPI (GPay, PhonePe, Paytm)', icon: '⚡' },
                { id: 'card', name: 'Credit / Debit Card', icon: '💳' },
                { id: 'netbanking', name: 'NetBanking', icon: '🏦' },
                { id: 'wallet', name: 'Wallets (Paytm, MobiKwik)', icon: '👛' }
              ].map((method) => (
                <label 
                  key={method.id}
                  className={`flex items-center gap-4 p-4 rounded-2xl border-2 cursor-pointer transition-all ${paymentMethod === method.id ? 'border-blue-500 bg-blue-50/50' : 'border-slate-100 hover:border-slate-200'}`}
                >
                  <input 
                    type="radio" 
                    name="payment" 
                    className="hidden" 
                    checked={paymentMethod === method.id}
                    onChange={() => setPaymentMethod(method.id)}
                  />
                  <span className="text-2xl">{method.icon}</span>
                  <span className="flex-1 font-semibold text-slate-700">{method.name}</span>
                  <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${paymentMethod === method.id ? 'border-blue-500 bg-blue-500' : 'border-slate-300'}`}>
                    {paymentMethod === method.id && <div className="w-2 h-2 rounded-full bg-white" />}
                  </div>
                </label>
              ))}
            </div>

            <button 
              onClick={handlePayment}
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-2xl shadow-lg transition-all flex items-center justify-center gap-2"
            >
              Pay ₹{hotel.totalPrice.toLocaleString('en-IN')}
            </button>
          </div>
        )}

        {step === 'processing' && (
          <div className="p-12 text-center space-y-6">
            <div className="relative h-20 w-20 mx-auto">
              <div className="absolute inset-0 rounded-full border-4 border-blue-100 border-t-blue-600 animate-spin"></div>
            </div>
            <h2 className="text-2xl font-bold text-slate-900">Securely Processing...</h2>
            <p className="text-slate-500">We are communicating with your bank to confirm the transaction. Please do not close this window.</p>
          </div>
        )}

        {step === 'failure' && (
          <div className="p-12 text-center space-y-6 animate-in slide-in-from-top-4">
            <div className="h-20 w-20 bg-red-100 text-red-600 rounded-full mx-auto flex items-center justify-center">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-10 h-10">
                <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </div>
            <div className="space-y-2">
              <h2 className="text-2xl font-bold text-slate-900">Payment Failed</h2>
              <p className="text-slate-500">{errorMessage || "Something went wrong during the transaction."}</p>
            </div>
            <div className="flex flex-col gap-3">
              <button 
                onClick={() => setStep('payment')}
                className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-2xl shadow-lg transition-all"
              >
                Retry Payment
              </button>
              <button 
                onClick={onClose}
                className="w-full bg-slate-100 hover:bg-slate-200 text-slate-700 font-bold py-4 rounded-2xl transition-all"
              >
                Cancel Booking
              </button>
            </div>
          </div>
        )}

        {step === 'success' && (
          <div className="p-12 text-center space-y-6">
            <div className="h-20 w-20 bg-green-100 text-green-600 rounded-full mx-auto flex items-center justify-center animate-bounce">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-10 h-10">
                <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" />
              </svg>
            </div>
            <div className="space-y-2">
              <h2 className="text-2xl font-bold text-slate-900">Booking Confirmed!</h2>
              <p className="text-slate-500">Your stay at {hotel.name} is all set. We've sent the confirmation to your email and WhatsApp.</p>
            </div>
            <button 
              onClick={onComplete}
              className="w-full bg-slate-900 hover:bg-slate-800 text-white font-bold py-4 rounded-2xl shadow-lg transition-all"
            >
              Done
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default BookingModal;

