import BookingModal from './components/BookingModal';
import { AppState, Hotel, AgentLog, ChatMessage, GroundingSource } from './types';
import { INDIA_DEFAULTS, TRENDING_SEARCHES } from './constants';
import { searchHotels, chatWithCrew } from './services/geminiService';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.LANDING);
  const [query, setQuery] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [groundingSources, setGroundingSources] = useState<GroundingSource[]>([]);
  const [agentLogs, setAgentLogs] = useState<AgentLog[]>([
    { agent: 'Research Specialist', status: 'pending', message: 'Searching multiple platforms...' },
    { agent: 'Review Analyst', status: 'pending', message: 'Analyzing sentiment from 1000s of reviews...' },
    { agent: 'Price Specialist', status: 'pending', message: 'Comparing rates across 8+ sources...' },
    { agent: 'Amenity Checker', status: 'pending', message: 'Verifying facilities & dietary options...' },
    { agent: 'Booking Coordinator', status: 'pending', message: 'Ready for final confirmation...' }
  ]);
  const [results, setResults] = useState<Hotel[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedHotel, setSelectedHotel] = useState<Hotel | null>(null);
  const [chatInput, setChatInput] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSearch = async (customQuery?: string) => {
    const activeQuery = customQuery || query;
    if (!activeQuery.trim()) return;

    setAppState(AppState.SEARCHING);
    setIsLoading(true);
    setMessages([{ 
      id: Date.now().toString(), 
      role: 'user', 
      content: activeQuery, 
      timestamp: new Date().toLocaleTimeString() 
    }]);

    setAgentLogs(prev => prev.map(l => ({ ...l, status: 'pending' })));

    try {
      const stepTimer = setInterval(() => {
        setAgentLogs(prev => {
          const firstPending = prev.findIndex(l => l.status === 'pending');
          if (firstPending === -1) return prev;
          const newLogs = [...prev];
          newLogs[firstPending].status = 'working';
          if (firstPending > 0) newLogs[firstPending - 1].status = 'completed';
          return newLogs;
        });
      }, 1500);

      const response = await searchHotels(activeQuery);
      clearInterval(stepTimer);

      setAgentLogs(prev => prev.map(l => ({ ...l, status: 'completed' })));
      setResults(response.hotels);
      setGroundingSources(response.sources || []);

      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: `Crew intelligence mission complete. I've analyzed ${response.sources?.length || 15} real-time global datasets. Top curated options for ${response.hotels[0]?.location.split(',')[0]} are ready.`,
        timestamp: new Date().toLocaleTimeString()
      }]);

      setAppState(AppState.RESULTS);
    } catch (error) {
      console.error(error);
      setAppState(AppState.LANDING);
    } finally {
      setIsLoading(false);
    }
  };

  const handleChat = async () => {
    if (!chatInput.trim() || isLoading) return;
    const userMsg = chatInput;
    setChatInput('');
    setMessages(prev => [...prev, {
      id: Date.now().toString(),
      role: 'user',
      content: userMsg,
      timestamp: new Date().toLocaleTimeString()
    }]);

    setIsLoading(true);
    try {
      const response = await chatWithCrew(userMsg, results);
      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: response || "Consulting with the agents...",
        timestamp: new Date().toLocaleTimeString()
      }]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col selection:bg-indigo-500 selection:text-white">
      <Header onLogoClick={() => setAppState(AppState.LANDING)} />

      <main className="flex-1 w-full max-w-7xl mx-auto px-6 py-12 md:py-20">
        {appState === AppState.LANDING && (
          <div className="flex flex-col items-center justify-center text-center space-y-16 py-10">
            <div className="space-y-8 max-w-4xl animate-in fade-in slide-in-from-bottom-8 duration-1000">
              <div className="inline-flex items-center gap-3 px-6 py-2 glass rounded-full text-xs font-black uppercase tracking-[0.3em] text-indigo-400 border-indigo-500/20 shadow-[0_0_20px_rgba(99,102,241,0.2)]">
                ✨ Next-Gen AI Travel Agent
              </div>
              <h1 className="text-5xl md:text-8xl font-black text-white leading-[1.1] tracking-tighter">
                Your AI Travel <br/>
                <span className="text-gradient">Crew Awaits</span>
              </h1>
              <p className="text-xl md:text-2xl text-white/50 max-w-2xl mx-auto font-medium leading-relaxed">
                Stop manual searching. Deploy our expert AI agents to find, compare, and secure your perfect stay in seconds.
              </p>
            </div>

            <div className="w-full max-w-4xl glass p-3 rounded-[2.5rem] shadow-[0_50px_100px_-20px_rgba(0,0,0,0.5)] border-white/10 animate-in zoom-in-95 duration-700 delay-300 relative group">
              <div className="absolute inset-0 bg-indigo-500/10 blur-[100px] opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
              <div className="flex flex-col md:flex-row gap-3 relative z-10">
                <input 
                  type="text" 
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
                  placeholder='Try "Business stay in Bangalore with fast WiFi, ₹6k budget"'
                  className="flex-1 bg-white/5 px-10 py-6 rounded-[2rem] text-xl text-white outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all placeholder:text-white/20 border border-white/5"
                />
                <button 
                  onClick={() => handleSearch()}
                  className="bg-gradient-glow text-white font-black py-6 px-12 rounded-[2rem] transition-all flex items-center justify-center gap-3 shadow-2xl hover:scale-[1.02] active:scale-95 hover:shadow-indigo-500/40"
                >
                  <span className="text-lg">Deploy Crew</span>
                  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-6 h-6">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
                  </svg>
                </button>
              </div>
            </div>

            <div className="w-full max-w-4xl grid grid-cols-1 md:grid-cols-2 gap-6 text-left animate-in fade-in duration-1000 delay-500">
              <h3 className="col-span-full text-[10px] font-black uppercase tracking-[0.3em] text-white/30 mb-2">🔥 Command Hotlinks</h3>
              {TRENDING_SEARCHES.map((item, idx) => (
                <button 
                  key={idx}
                  onClick={() => handleSearch(item.query)}
                  className="p-6 glass rounded-3xl border-white/5 hover:border-indigo-500/30 hover:bg-white/10 transition-all group flex items-center justify-between"
                >
                  <div className="flex flex-col gap-1">
                    <span className="font-bold text-white group-hover:text-indigo-400 transition-colors">{item.label}</span>
                    <span className="text-xs text-white/40 uppercase font-black tracking-widest">{item.budget}</span>
                  </div>
                  <div className="h-10 w-10 rounded-2xl bg-white/5 flex items-center justify-center text-white/20 group-hover:bg-indigo-500 group-hover:text-white transition-all">
                    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-5 h-5">
                      <path strokeLinecap="round" strokeLinejoin="round" d="M12 4.5v15m7.5-7.5h-15" />
                    </svg>
                  </div>
                </button>
              ))}
            </div>

            <section className="grid grid-cols-1 md:grid-cols-3 gap-16 pt-20 text-center max-w-5xl">
              <div className="space-y-4">
                <div className="h-16 w-16 glass rounded-2xl mx-auto flex items-center justify-center text-indigo-400 font-black text-2xl border-indigo-500/20">01</div>
                <h4 className="font-black text-white text-lg uppercase tracking-wider">Natural Intent</h4>
                <p className="text-sm text-white/40 leading-relaxed">No complex forms. Just tell us your vibe, budget, and needs in plain English.</p>
              </div>
              <div className="space-y-4">
                <div className="h-16 w-16 glass rounded-2xl mx-auto flex items-center justify-center text-indigo-400 font-black text-2xl border-indigo-500/20">02</div>
                <h4 className="font-black text-white text-lg uppercase tracking-wider">Parallel Agency</h4>
                <p className="text-sm text-white/40 leading-relaxed">5 specialized AI agents research, verify, and compare deals in real-time.</p>
              </div>
              <div className="space-y-4">
                <div className="h-16 w-16 glass rounded-2xl mx-auto flex items-center justify-center text-indigo-400 font-black text-2xl border-indigo-500/20">03</div>
                <h4 className="font-black text-white text-lg uppercase tracking-wider">Direct Checkout</h4>
                <p className="text-sm text-white/40 leading-relaxed">Secure UPI and card payments integrated directly into the command center.</p>
              </div>
            </section>
          </div>
        )}

        {(appState === AppState.SEARCHING || appState === AppState.RESULTS || appState === AppState.BOOKING) && (
          <div className="flex flex-col gap-12 pb-32 animate-in fade-in duration-500">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 border-b border-white/5 pb-8">
              <div className="space-y-1">
                <button 
                  onClick={() => setAppState(AppState.LANDING)}
                  className="flex items-center gap-2 text-indigo-400 hover:text-white font-black text-xs uppercase tracking-widest transition-all mb-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-4 h-4">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 19.5L8.25 12l7.5-7.5" />
                  </svg>
                  Terminate Mission
                </button>
                <h2 className="text-3xl font-black text-white">Active Intelligence Mission</h2>
              </div>
              <div className="flex items-center gap-4 glass px-6 py-3 rounded-[1.5rem] border-indigo-500/20">
                <div className="flex -space-x-3">
                  {[1,2,3,4,5].map(i => <div key={i} className="h-10 w-10 rounded-full bg-indigo-600 border-2 border-slate-950 flex items-center justify-center text-[10px] font-black text-white shadow-xl">A{i}</div>)}
                </div>
                <div className="h-2 w-2 rounded-full bg-indigo-500 animate-ping"></div>
                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.2em]">Operational</span>
              </div>
            </div>

            <div className="flex flex-col gap-6 max-h-[500px] overflow-y-auto pr-4 scrollbar-hide custom-scrollbar">
              {messages.map(msg => (
                <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-4`}>
                  <div className={`max-w-[75%] p-6 rounded-[2rem] shadow-2xl ${msg.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'glass border-white/10 rounded-tl-none text-white/90'}`}>
                    <p className="text-md leading-relaxed font-medium whitespace-pre-wrap">{msg.content}</p>
                    <span className={`text-[10px] font-black uppercase tracking-widest mt-4 block opacity-40 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                      {msg.timestamp}
                    </span>
                  </div>
                </div>
              ))}
              <div ref={chatEndRef} />
            </div>

            <AgentStatusPanel logs={agentLogs} />

            {appState === AppState.RESULTS && (
              <div className="space-y-20">
                <div className="text-center space-y-4">
                  <h3 className="text-5xl font-black text-white tracking-tighter">Curated Top Matches</h3>
                  <p className="text-white/40 text-lg font-medium">Mission success. Here are the 3 most qualified options analyzed by our agents.</p>
                </div>

                <div className="grid grid-cols-1 gap-12">
                  {results.map((hotel) => (
                    <HotelCard key={hotel.id} hotel={hotel} onBook={(h) => { setSelectedHotel(h); setAppState(AppState.BOOKING); }} />
                  ))}
                </div>

                <div className="fixed bottom-0 left-0 right-0 glass border-t border-white/10 p-6 z-50 shadow-[0_-20px_50px_rgba(0,0,0,0.5)]">
                  <div className="max-w-7xl mx-auto flex gap-4">
                    <div className="flex-1 relative">
                      <input 
                        type="text" 
                        value={chatInput}
                        onChange={(e) => setChatInput(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleChat()}
                        placeholder="Type follow-up commands to your AI Crew..."
                        className="w-full bg-white/5 border border-white/10 rounded-2xl px-8 py-5 outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all text-white font-medium"
                      />
                      <div className="absolute right-6 top-1/2 -translate-y-1/2 flex gap-3">
                        <button className="text-white/20 hover:text-white transition-colors">🎤</button>
                        <button className="text-white/20 hover:text-white transition-colors">💰</button>
                      </div>
                    </div>
                    <button 
                      disabled={isLoading}
                      onClick={handleChat}
                      className="bg-white text-slate-900 font-black px-12 py-5 rounded-2xl hover:bg-indigo-50 disabled:opacity-50 transition-all active:scale-95 flex items-center gap-2"
                    >
                      {isLoading ? 'Wait...' : 'Execute'}
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>
        )}

        {selectedHotel && appState === AppState.BOOKING && (
          <BookingModal 
            hotel={selectedHotel} 
            onClose={() => setAppState(AppState.RESULTS)}
            onComplete={() => {
              setAppState(AppState.LANDING);
              setSelectedHotel(null);
            }}
          />
        )}
      </main>

      <footer className="glass-dark border-t border-white/5 py-20 mt-20">
        <div className="max-w-7xl mx-auto px-6 grid grid-cols-1 md:grid-cols-4 gap-16">
          <div className="space-y-6">
            <div className="flex items-center gap-3">
              <div className="h-10 w-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-xl">
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-5 h-5">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M6 12L3.269 3.126A59.768 59.768 0 0121.485 12 59.77 59.77 0 013.27 20.876L5.999 12zm0 0h7.5" />
                </svg>
              </div>
              <span className="text-2xl font-black text-white">TravelCrew AI</span>
            </div>
            <p className="text-white/40 leading-relaxed font-medium">
              Revolutionizing travel through autonomous agent intelligence. Built for the modern traveler.
            </p>
          </div>
          <div>
            <h5 className="text-indigo-400 font-black uppercase text-[10px] tracking-[0.3em] mb-8">Navigation</h5>
            <ul className="space-y-4 text-sm font-bold text-white/50">
              <li><a href="#" className="hover:text-white transition-colors">Deployment Nodes</a></li>
              <li><a href="#" className="hover:text-white transition-colors">Agent Framework</a></li>
              <li><a href="#" className="hover:text-white transition-colors">API Keys</a></li>
              <li><a href="#" className="hover:text-white transition-colors">Global Network</a></li>
            </ul>
          </div>
          <div>
            <h5 className="text-indigo-400 font-black uppercase text-[10px] tracking-[0.3em] mb-8">Security</h5>
            <ul className="space-y-4 text-sm font-bold text-white/50">
              <li><a href="#" className="hover:text-white transition-colors">Quantum Privacy</a></li>
              <li><a href="#" className="hover:text-white transition-colors">Payment Shield</a></li>
              <li><a href="#" className="hover:text-white transition-colors">Verified Stays</a></li>
            </ul>
          </div>
          <div className="glass p-8 rounded-3xl border-white/5">
            <h5 className="text-white font-black mb-4 uppercase text-[10px] tracking-widest">Connect Hub</h5>
            <p className="mb-6 text-xs text-white/40 font-medium">Join 50k+ travelers using agentic booking.</p>
            <button className="w-full bg-white text-slate-900 py-4 rounded-xl font-black hover:bg-indigo-50 transition-all text-xs uppercase tracking-widest">Subscribe</button>
          </div>
        </div>
        <div className="max-w-7xl mx-auto px-6 mt-20 pt-10 border-t border-white/5 text-center text-[10px] font-black uppercase tracking-[0.5em] text-white/20">
          © 2024 TravelCrew AI Platform | Powered by Gemini 3 Intelligence
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Hotel } from '../types';
import { INDIA_DEFAULTS } from '../constants';

interface BookingModalProps {
  hotel: Hotel;
  onClose: () => void;
  onComplete: () => void;
}

const BookingModal: React.FC<BookingModalProps> = ({ hotel, onClose, onComplete }) => {
  const [step, setStep] = useState<'details' | 'payment' | 'processing' | 'success' | 'failure'>('details');
  const [paymentMethod, setPaymentMethod] = useState('upi');
  const [errorMessage, setErrorMessage] = useState('');

  const handlePayment = () => {
    setStep('processing');
    setErrorMessage('');
    setTimeout(() => {
      const isSuccessful = Math.random() > 0.2;
      if (isSuccessful) {
        setStep('success');
      } else {
        const errors = [
          "Transaction declined by your bank. Verify limits.",
          "Payment gateway timeout. Retrying node...",
          "UPI authentication failed.",
          "Session expired. Refreshing command."
        ];
        setErrorMessage(errors[Math.floor(Math.random() * errors.length)]);
        setStep('failure');
      }
    }, 2500);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/90 backdrop-blur-xl animate-in fade-in duration-300">
      <div className="glass w-full max-w-xl rounded-[3rem] overflow-hidden shadow-[0_50px_100px_rgba(0,0,0,0.8)] border-white/10 animate-in zoom-in-95 duration-500">

        {step === 'details' && (
          <div className="p-10 md:p-12">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-3xl font-black text-white">Review Order</h2>
              <button onClick={onClose} className="h-12 w-12 glass border-white/10 rounded-full flex items-center justify-center text-white/40 hover:text-white transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-6 h-6">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>

            <div className="flex gap-6 mb-10 p-6 glass rounded-3xl border-white/10">
              <img src={hotel.image} className="w-24 h-24 rounded-2xl object-cover border border-white/10" />
              <div className="flex flex-col justify-center">
                <h4 className="text-xl font-bold text-white">{hotel.name}</h4>
                <p className="text-sm text-white/40 font-bold uppercase tracking-widest mt-1">{hotel.location}</p>
                <div className="mt-2 text-indigo-400 font-black">₹{hotel.pricePerNight.toLocaleString('en-IN')} / night</div>
              </div>
            </div>

            <div className="space-y-4 mb-10 px-2">
              <div className="flex justify-between text-sm">
                <span className="text-white/40 font-bold uppercase tracking-widest">Duration</span>
                <span className="text-white font-bold">2 Nights</span>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-white/40 font-bold uppercase tracking-widest">Occupancy</span>
                <span className="text-white font-bold">2 Adults</span>
              </div>
              <div className="flex justify-between text-sm border-t border-white/5 pt-6 mt-6">
                <span className="text-white/60 font-bold uppercase tracking-[0.2em]">Total Charge</span>
                <span className="text-3xl font-black text-white">₹{hotel.totalPrice.toLocaleString('en-IN')}</span>
              </div>
            </div>

            <button 
              onClick={() => setStep('payment')}
              className="w-full bg-white text-slate-950 font-black py-6 rounded-[1.5rem] shadow-2xl hover:bg-indigo-50 transition-all hover:scale-[1.02] active:scale-95 text-lg"
            >
              Verify & Proceed
            </button>
          </div>
        )}

        {step === 'payment' && (
          <div className="p-10 md:p-12">
            <div className="flex items-center gap-6 mb-10">
              <button onClick={() => setStep('details')} className="h-12 w-12 glass border-white/10 rounded-full flex items-center justify-center text-white/40 hover:text-white">
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-5 h-5">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 19.5L8.25 12l7.5-7.5" />
                </svg>
              </button>
              <h2 className="text-2xl font-black text-white">Secure Payment</h2>
            </div>

            <div className="space-y-4 mb-10">
              {[
                { id: 'upi', name: 'Unified Payments Interface (UPI)', icon: '⚡' },
                { id: 'card', name: 'Credit / Debit Card Protocol', icon: '💳' },
                { id: 'netbanking', name: 'Secure NetBanking', icon: '🏦' }
              ].map((method) => (
                <label 
                  key={method.id}
                  className={`flex items-center gap-5 p-6 rounded-[1.5rem] border cursor-pointer transition-all duration-300 ${paymentMethod === method.id ? 'border-indigo-500 bg-indigo-500/10' : 'border-white/5 hover:bg-white/5'}`}
                >
                  <input type="radio" name="payment" className="hidden" checked={paymentMethod === method.id} onChange={() => setPaymentMethod(method.id)} />
                  <span className="text-2xl">{method.icon}</span>
                  <span className="flex-1 font-bold text-white/80">{method.name}</span>
                  <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${paymentMethod === method.id ? 'border-indigo-500 bg-indigo-500' : 'border-white/20'}`}>
                    {paymentMethod === method.id && <div className="w-2 h-2 rounded-full bg-white" />}
                  </div>
                </label>
              ))}
            </div>

            <button 
              onClick={handlePayment}
              className="w-full bg-white text-slate-950 font-black py-6 rounded-[1.5rem] shadow-2xl transition-all hover:scale-[1.02] active:scale-95 text-lg"
            >
              Confirm ₹{hotel.totalPrice.toLocaleString('en-IN')}
            </button>
          </div>
        )}

        {step === 'processing' && (
          <div className="p-20 text-center space-y-8">
            <div className="relative h-24 w-24 mx-auto">
              <div className="absolute inset-0 rounded-full border-4 border-white/5 border-t-indigo-500 animate-spin"></div>
            </div>
            <div className="space-y-2">
              <h2 className="text-2xl font-black text-white">Encryption Protocol Active</h2>
              <p className="text-white/40 text-sm font-medium">Securing transaction via banking nodes...</p>
            </div>
          </div>
        )}

        {step === 'failure' && (
          <div className="p-16 text-center space-y-8 animate-in slide-in-from-top-4">
            <div className="h-20 w-20 bg-red-500/20 text-red-500 rounded-full mx-auto flex items-center justify-center shadow-[0_0_30px_rgba(239,68,68,0.3)]">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-10 h-10">
                <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </div>
            <div className="space-y-3">
              <h2 className="text-3xl font-black text-white">Transaction Fault</h2>
              <p className="text-white/50 font-medium px-4">{errorMessage}</p>
            </div>
            <div className="flex flex-col gap-4">
              <button onClick={() => setStep('payment')} className="w-full bg-white text-slate-950 font-black py-5 rounded-2xl hover:scale-[1.02] transition-all">
                Retry Connection
              </button>
              <button onClick={onClose} className="w-full text-white/40 font-bold py-2 hover:text-white transition-all uppercase text-xs tracking-widest">
                Abort Booking
              </button>
            </div>
          </div>
        )}

        {step === 'success' && (
          <div className="p-16 text-center space-y-8 animate-in zoom-in-95 duration-700">
            <div className="h-24 w-24 bg-indigo-500/20 text-indigo-400 rounded-full mx-auto flex items-center justify-center shadow-[0_0_50px_rgba(99,102,241,0.5)] animate-bounce">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={4} stroke="currentColor" className="w-12 h-12">
                <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" />
              </svg>
            </div>
            <div className="space-y-3">
              <h2 className="text-4xl font-black text-white">Mission Confirmed</h2>
              <p className="text-white/40 font-medium">Your stay at {hotel.name} is verified. Deployment packets sent to WhatsApp & Email.</p>
            </div>
            <button 
              onClick={onComplete}
              className="w-full bg-white text-slate-950 font-black py-6 rounded-2xl shadow-2xl transition-all hover:scale-[1.02] active:scale-95"
            >
              Return to Hub
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

