      case AppState.DEPLOYMENT_MUMBAI:
        return <PlaceholderView title="Mumbai Data Center" icon="⚡" description="Primary node in Maharashtra handling 60% of all Indian travel queries with sub-millisecond latency." stats={[{ label: 'Uptime', value: '99.9%', sub: 'Last 12 Months', color: 'text-emerald-400' }, { label: 'Speed', value: '45s', sub: 'Avg AI Execution' }, { label: 'Capacity', value: '50k', sub: 'Concurrent Missions' }]} />;
