import { GoogleGenAI, Type } from "@google/genai";
import { Hotel } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const HOTEL_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    hotels: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          name: { type: Type.STRING },
          rating: { type: Type.NUMBER },
          location: { type: Type.STRING },
          pricePerNight: { type: Type.NUMBER },
          totalPrice: { type: Type.NUMBER },
          image: { type: Type.STRING },
          description: { type: Type.STRING },
          whyPerfect: { type: Type.ARRAY, items: { type: Type.STRING } },
          aiAnalysis: {
            type: Type.OBJECT,
            properties: {
              positive: { type: Type.ARRAY, items: { type: Type.STRING } },
              concerns: { type: Type.ARRAY, items: { type: Type.STRING } }
            }
          },
          inclusions: { type: Type.ARRAY, items: { type: Type.STRING } },
          comparisons: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                platform: { type: Type.STRING },
                price: { type: Type.NUMBER },
                isBest: { type: Type.BOOLEAN }
              }
            }
          },
          tag: { type: Type.STRING }
        }
      }
    }
  },
  required: ["hotels"]
};

export async function searchHotels(userInput: string) {
  const prompt = `
    You are the lead manager of TravelCrew AI, an advanced multi-agent hotel research platform for India.
    User Request: "${userInput}"

    CRITICAL: You are managing a crew of 5 agents:
    1. Research Agent: Finds actual hotels in India or specified international spots.
    2. Review Analyst: Analyzes real user sentiment (especially cleanliness and food).
    3. Price Agent: Finds best deals.
    4. Amenity Agent: Verifies specific Indian preferences like Pure Veg, Jain Food, or Family Rooms.
    5. Booking Coordinator: Prepares final selection.

    TASK: Perform research using Google Search and return exactly 3 top hotel recommendations in JSON format.
    - "BEST MATCH": The most balanced option.
    - "BUDGET CHOICE": For value-conscious travelers.
    - "PREMIUM UPGRADE": A luxury alternative.

    Currency: INR (₹). Use realistic price ranges for the destination.
    Dates: If not specified, assume 2 nights starting this Friday.
  `;

  console.debug("Deploying Mission with prompt:", prompt);

  try {
    // Switched to flash-preview for much faster response times as per user feedback
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: HOTEL_SCHEMA,
        tools: [{ googleSearch: {} }]
      },
    });

    const responseText = response.text;
    console.debug("Raw Gemini Response:", responseText);

    if (!responseText) {
      throw new Error("Empty response from Gemini API");
    }

    let json;
    try {
      json = JSON.parse(responseText);
    } catch (e) {
      console.error("JSON Parse Error. Raw Text:", responseText);
      throw new Error("Failed to parse AI response as JSON");
    }

    if (!json.hotels || !Array.isArray(json.hotels)) {
      throw new Error("Invalid response format: 'hotels' array missing");
    }

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        title: chunk.web?.title || 'Research Source',
        uri: chunk.web?.uri || ''
      })).filter((s: any) => s.uri) || [];

    return { ...json, sources };
  } catch (error: any) {
    console.error("Gemini Search Error:", error);
    throw error;
  }
}

export async function chatWithCrew(userInput: string, context: Hotel[]) {
  const prompt = `
    You are the TravelCrew AI Assistant. You have already found these hotels for the user:
    ${JSON.stringify(context)}

    The user is asking: "${userInput}"

    Provide a helpful, expert response as if you are coordinating with your research crew.
    Keep it concise and focus on Indian traveler needs (food, safety, value).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    console.error("Chat Error:", error);
    return "I'm having trouble reaching my research crew right now. How else can I help?";
  }
}

import React, { useState, useRef, useEffect } from 'react';
import Header from './components/Header';
import Footer from './components/Footer';
import AgentStatusPanel from './components/AgentStatusPanel';
import HotelCard from './components/HotelCard';
import BookingModal from './components/BookingModal';
import { AppState, Hotel, AgentLog, ChatMessage, GroundingSource } from './types';
import { INDIA_DEFAULTS, TRENDING_SEARCHES } from './constants';
import { searchHotels, chatWithCrew } from './services/geminiService';

const ESTIMATED_DEPLOY_TIME = 25; // Estimated seconds for Gemini-3-Flash mission

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.LANDING);
  const [query, setQuery] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [groundingSources, setGroundingSources] = useState<GroundingSource[]>([]);
  const [agentLogs, setAgentLogs] = useState<AgentLog[]>([
    { agent: 'Research Specialist', status: 'pending', message: 'Searching multiple platforms...' },
    { agent: 'Review Analyst', status: 'pending', message: 'Analyzing sentiment from 1000s of reviews...' },
    { agent: 'Price Specialist', status: 'pending', message: 'Comparing rates across 8+ sources...' },
    { agent: 'Amenity Checker', status: 'pending', message: 'Verifying facilities & dietary options...' },
    { agent: 'Booking Coordinator', status: 'pending', message: 'Ready for final confirmation...' }
  ]);
  const [results, setResults] = useState<Hotel[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedHotel, setSelectedHotel] = useState<Hotel | null>(null);
  const [chatInput, setChatInput] = useState('');
  const [missionTimer, setMissionTimer] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  useEffect(() => {
    if (isLoading && (appState === AppState.SEARCHING)) {
      const start = Date.now();
      timerRef.current = window.setInterval(() => {
        setMissionTimer(Math.floor((Date.now() - start) / 1000));
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isLoading, appState]);

  const handleSearch = async (customQuery?: string) => {
    const activeQuery = customQuery || query;
    if (!activeQuery.trim()) return;

    setError(null);
    setAppState(AppState.SEARCHING);
    setIsLoading(true);
    setMissionTimer(0);
    setMessages([{ 
      id: Date.now().toString(), 
      role: 'user', 
      content: activeQuery, 
      timestamp: new Date().toLocaleTimeString() 
    }]);

    setAgentLogs(prev => prev.map(l => ({ ...l, status: 'pending' })));

    try {
      // Step timer for visual feedback - slightly faster now to match Flash model
      const stepTimer = window.setInterval(() => {
        setAgentLogs(prev => {
          const firstPending = prev.findIndex(l => l.status === 'pending');
          if (firstPending === -1) return prev;
          const newLogs = [...prev];
          newLogs[firstPending].status = 'working';
          if (firstPending > 0) newLogs[firstPending - 1].status = 'completed';
          return newLogs;
        });
      }, 1500);

      const response = await searchHotels(activeQuery);
      clearInterval(stepTimer);

      setAgentLogs(prev => prev.map(l => ({ ...l, status: 'completed' })));

      const hotels = response.hotels || [];
      setResults(hotels);
      setGroundingSources(response.sources || []);

      const locationName = hotels[0]?.location ? hotels[0].location.split(',')[0] : 'your destination';

      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: `Crew mission success. Analyzed ${response.sources?.length || 0} datasets. Recommendations for ${locationName} mapped to your intent.`,
        timestamp: new Date().toLocaleTimeString()
      }]);

      setAppState(AppState.RESULTS);
    } catch (error: any) {
      console.error("handleSearch Error:", error);
      setError(error.message || "A deployment error occurred. Please try again.");
      setAppState(AppState.LANDING);
    } finally {
      setIsLoading(false);
    }
  };

  const handleChat = async () => {
    if (!chatInput.trim() || isLoading) return;
    const userMsg = chatInput;
    setChatInput('');
    setMessages(prev => [...prev, {
      id: Date.now().toString(),
      role: 'user',
      content: userMsg,
      timestamp: new Date().toLocaleTimeString()
    }]);

    setIsLoading(true);
    try {
      const response = await chatWithCrew(userMsg, results);
      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: response || "The crew is verifying details...",
        timestamp: new Date().toLocaleTimeString()
      }]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const onNavigate = (view: AppState) => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setError(null);
    setAppState(view);
  };

  // Sections
  const DestinationsView = () => (
