                <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-4`}>
                  <div className={`max-w-[75%] p-6 rounded-[2rem] shadow-2xl ${msg.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'glass border-white/10 rounded-tl-none text-white/90'}`}>
                    <p className="text-md leading-relaxed font-medium whitespace-pre-wrap">{msg.content}</p>
                    <span className={`text-[10px] font-black uppercase tracking-widest mt-4 block opacity-40 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>{msg.timestamp}</span>
                  </div>
                </div>
              ))}
              <div ref={chatEndRef} />
            </div>

            <AgentStatusPanel logs={agentLogs} />

            {appState === AppState.RESULTS && (
              <div className="space-y-20">
                <div className="text-center space-y-4">
                  <h3 className="text-5xl font-black text-white tracking-tighter">Mission Results</h3>
                  <p className="text-white/40 text-lg font-medium">Mission completed in {missionTimer} seconds.</p>
                </div>
                {results.length > 0 ? (
                  <div className="grid grid-cols-1 gap-12">{results.map((hotel) => (<HotelCard key={hotel.id} hotel={hotel} onBook={(h) => { setSelectedHotel(h); setAppState(AppState.BOOKING); }} />))}</div>
                ) : (
                  <div className="text-center py-20 glass rounded-[3rem] border-white/10">
                    <p className="text-white/40 font-bold">The crew couldn't find matches for this specific query. Try refining your budget or location.</p>
                  </div>
                )}

                <div className="fixed bottom-0 left-0 right-0 glass border-t border-white/10 p-6 z-50 shadow-[0_-20px_50px_rgba(0,0,0,0.5)]">
                  <div className="max-w-7xl mx-auto flex gap-4">
                    <input type="text" value={chatInput} onChange={(e) => setChatInput(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleChat()} placeholder="Ask follow-up commands to your AI Crew..." className="flex-1 bg-white/5 border border-white/10 rounded-2xl px-8 py-5 outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all text-white font-medium" />
                    <button 
                      onClick={handleChat} 
                      disabled={isLoading} 
                      className="bg-white text-slate-900 font-bold px-12 py-5 rounded-full hover:shadow-lg transition-all disabled:opacity-50 uppercase tracking-widest text-sm"
                    >
                      Execute
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>
        );
      default:
        return (
          <div className="max-w-4xl mx-auto py-12 text-center space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-700">
            <h1 className="text-4xl md:text-6xl font-black uppercase tracking-tighter">{appState.replace('_', ' ')}</h1>
            <p className="text-xl text-white/50 leading-relaxed font-medium">Node under maintenance or indexing by agents. Deployment in progress.</p>
            <button onClick={() => onNavigate(AppState.LANDING)} className="px-10 py-5 bg-white text-slate-900 rounded-full font-bold uppercase tracking-widest text-xs hover:shadow-lg transition-all">Return to Command Hub</button>
          </div>
        );
    }
  };

  return (
    <div className="min-h-screen flex flex-col selection:bg-indigo-500 selection:text-white">
      <Header onNavigate={onNavigate} currentView={appState} />
      <main className="flex-1 w-full max-w-7xl mx-auto px-6 py-12 md:py-20">
        {renderContent()}
        {selectedHotel && appState === AppState.BOOKING && (
          <BookingModal hotel={selectedHotel} onClose={() => setAppState(AppState.RESULTS)} onComplete={() => { setAppState(AppState.LANDING); setSelectedHotel(null); }} />
        )}
      </main>
      <Footer onNavigate={onNavigate} />
    </div>
  );
};

