export interface Hotel {
  id: string;
  name: string;
  rating: number;
  location: string;
  pricePerNight: number;
  totalPrice: number;
  image: string;
  description: string;
  whyPerfect: string[];
  aiAnalysis: {
    positive: string[];
    concerns: string[];
  };
  inclusions: string[];
  comparisons: {
    platform: string;
    price: number;
    isBest?: boolean;
  }[];
  tag?: string; // e.g., "BEST MATCH", "BUDGET OPTION"
}

export interface GroundingSource {
  title: string;
  uri: string;
}

export interface AgentLog {
  agent: string;
  status: 'pending' | 'working' | 'completed';
  message: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: string;
}

export enum AppState {
  LANDING = 'landing',
  SEARCHING = 'searching',
  RESULTS = 'results',
  BOOKING = 'booking',
  FLIGHTS = 'flights',
  DESTINATIONS = 'destinations',
  SUPPORT = 'support',
  PROFILE = 'profile',
  DEPLOYMENT_MUMBAI = 'mumbai',
  DEPLOYMENT_BANGALORE = 'bangalore',
  DEPLOYMENT_CDN = 'cdn',
  DEPLOYMENT_EDGE = 'edge',
  AGENTS_RESEARCH = 'research',
  AGENTS_REVIEWS = 'reviews',
  AGENTS_PRICING = 'pricing',
  AGENTS_BOOKING = 'booking_agent',
  HOW_IT_WORKS = 'how-it-works',
  SECURITY_PRIVACY = 'quantum-privacy',
  SECURITY_PAYMENTS = 'payment-shield',
  SECURITY_VERIFICATION = 'verified-stays',
  TERMS = 'terms',
  PRIVACY = 'privacy',
  CONTACT = 'contact',
  DEVELOPERS = 'developers'
}

import React, { useState, useRef, useEffect } from 'react';
import Header from './components/Header';
import Footer from './components/Footer';
import AgentStatusPanel from './components/AgentStatusPanel';
import HotelCard from './components/HotelCard';
import BookingModal from './components/BookingModal';
import ProfileView from './components/ProfileView';
import { AppState, Hotel, AgentLog, ChatMessage, GroundingSource } from './types';
import { INDIA_DEFAULTS, TRENDING_SEARCHES } from './constants';
import { searchHotels, chatWithCrew } from './services/geminiService';

const ESTIMATED_DEPLOY_TIME = 25; // Estimated seconds for Gemini-3-Flash mission

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.LANDING);
  const [query, setQuery] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [groundingSources, setGroundingSources] = useState<GroundingSource[]>([]);
  const [agentLogs, setAgentLogs] = useState<AgentLog[]>([
    { agent: 'Research Specialist', status: 'pending', message: 'Searching multiple platforms...' },
    { agent: 'Review Analyst', status: 'pending', message: 'Analyzing sentiment from 1000s of reviews...' },
    { agent: 'Price Specialist', status: 'pending', message: 'Comparing rates across 8+ sources...' },
    { agent: 'Amenity Checker', status: 'pending', message: 'Verifying facilities & dietary options...' },
    { agent: 'Booking Coordinator', status: 'pending', message: 'Ready for final confirmation...' }
  ]);
  const [results, setResults] = useState<Hotel[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedHotel, setSelectedHotel] = useState<Hotel | null>(null);
  const [chatInput, setChatInput] = useState('');
  const [missionTimer, setMissionTimer] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  useEffect(() => {
    if (isLoading && (appState === AppState.SEARCHING)) {
      const start = Date.now();
      timerRef.current = window.setInterval(() => {
        setMissionTimer(Math.floor((Date.now() - start) / 1000));
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isLoading, appState]);

  const handleSearch = async (customQuery?: string) => {
    const activeQuery = customQuery || query;
    if (!activeQuery.trim()) return;

    setError(null);
    setAppState(AppState.SEARCHING);
    setIsLoading(true);
    setMissionTimer(0);
    setMessages([{ 
      id: Date.now().toString(), 
      role: 'user', 
      content: activeQuery, 
      timestamp: new Date().toLocaleTimeString() 
    }]);

    setAgentLogs(prev => prev.map(l => ({ ...l, status: 'pending' })));

    try {
      // Step timer for visual feedback - slightly faster now to match Flash model
      const stepTimer = window.setInterval(() => {
        setAgentLogs(prev => {
          const firstPending = prev.findIndex(l => l.status === 'pending');
          if (firstPending === -1) return prev;
          const newLogs = [...prev];
          newLogs[firstPending].status = 'working';
          if (firstPending > 0) newLogs[firstPending - 1].status = 'completed';
          return newLogs;
        });
      }, 1500);

      const response = await searchHotels(activeQuery);
      clearInterval(stepTimer);

      setAgentLogs(prev => prev.map(l => ({ ...l, status: 'completed' })));

      const hotels = response.hotels || [];
      setResults(hotels);
      setGroundingSources(response.sources || []);

      const locationName = hotels[0]?.location ? hotels[0].location.split(',')[0] : 'your destination';

      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: `Crew mission success. Analyzed ${response.sources?.length || 0} datasets. Recommendations for ${locationName} mapped to your intent.`,
        timestamp: new Date().toLocaleTimeString()
      }]);

      setAppState(AppState.RESULTS);
    } catch (error: any) {
      console.error("handleSearch Error:", error);
      setError(error.message || "A deployment error occurred. Please try again.");
      setAppState(AppState.LANDING);
    } finally {
      setIsLoading(false);
    }
  };

  const handleChat = async () => {
    if (!chatInput.trim() || isLoading) return;
    const userMsg = chatInput;
    setChatInput('');
    setMessages(prev => [...prev, {
      id: Date.now().toString(),
      role: 'user',
      content: userMsg,
      timestamp: new Date().toLocaleTimeString()
    }]);

    setIsLoading(true);
    try {
      const response = await chatWithCrew(userMsg, results);
      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: response || "The crew is verifying details...",
        timestamp: new Date().toLocaleTimeString()
      }]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const onNavigate = (view: AppState) => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setError(null);
    setAppState(view);
  };

  // Sections
  const DestinationsView = () => (
    <div className="space-y-20 py-12 animate-in fade-in slide-in-from-bottom-8 duration-1000">
      <div className="text-center max-w-4xl mx-auto space-y-4">
        <h1 className="text-5xl md:text-7xl font-black text-white tracking-tighter">AI-Curated <span className="text-gradient">Hubs</span></h1>
        <p className="text-xl text-white/50 font-medium">Deployment-ready destinations optimized for the Indian context.</p>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
        {[
          { 
            title: "The Golden Triangle", 
            subtitle: "Delhi-Agra-Jaipur", 
            desc: "Beyond the monuments. Our agents find boutique havelis with verified 5-star hospitality.",
            img: "https://images.unsplash.com/photo-1599661046289-e31897846e41?auto=format&fit=crop&q=80&w=800" 
          },
          { 
            title: "Goa Coastal Command", 
            subtitle: "Beach & Veg Focus", 
            desc: "From North Goa’s energy to South Goa’s serenity. Filters prioritized for private beach access.",
            img: "https://images.unsplash.com/photo-1512343879784-a960bf40e7f2?auto=format&fit=crop&q=80&w=800" 
          },
          { 
            title: "Spirit of Varanasi", 
            subtitle: "Digital Nomad Hub", 
            desc: "Curated stays near the Ghats with high-speed WiFi for the modern traveler.",
            img: "https://images.unsplash.com/photo-1561359313-0639aad49ca6?auto=format&fit=crop&q=80&w=800" 
          },
          { 
            title: "Himalayan Circuit", 
            subtitle: "Safety Grounding", 
            desc: "Real-time weather grounding to find the safest, most scenic retreats in Manali and Leh.",
            img: "https://images.unsplash.com/photo-1544620347-c4fd4a3d5957?auto=format&fit=crop&q=80&w=800" 
          }
        ].map((dest, i) => (
          <div key={i} className="glass rounded-[2.5rem] overflow-hidden group border border-white/10 hover:border-indigo-500/30 transition-all duration-500 hover:shadow-2xl">
            <div className="h-64 overflow-hidden relative">
              <img src={dest.img} className="w-full h-full object-cover animate-ken-burns group-hover:scale-110 transition-transform duration-1000" />
              <div className="absolute inset-0 bg-gradient-to-t from-slate-950 to-transparent opacity-60"></div>
              <div className="absolute bottom-6 left-6">
                <span className="text-[10px] font-black uppercase tracking-[0.3em] text-indigo-400">{dest.subtitle}</span>
                <h3 className="text-2xl font-black text-white">{dest.title}</h3>
              </div>
