import React, { useState, useEffect, useRef } from 'react';
import { motion } from 'framer-motion';
import { Hotel } from '../types';
import { INDIA_DEFAULTS } from '../constants';
import AgenticButton from './AgenticButton';

interface BookingModalProps {
  hotel: Hotel;
  onClose: () => void;
  onComplete: () => void;
}

const BookingModal: React.FC<BookingModalProps> = ({ hotel, onClose, onComplete }) => {
  const [step, setStep] = useState<'details' | 'guestInfo' | 'payment' | 'processing' | 'success' | 'failure'>('details');
  const [paymentMethod, setPaymentMethod] = useState('upi');
  const [errorMessage, setErrorMessage] = useState('');
  const [guestInfo, setGuestInfo] = useState({ name: '', email: '', phone: '' });
  const [processingTime, setProcessingTime] = useState(0);
  const processingTimerRef = useRef<number | null>(null);

  useEffect(() => {
    if (step === 'processing') {
      const start = Date.now();
      processingTimerRef.current = window.setInterval(() => {
        setProcessingTime(Math.floor((Date.now() - start) / 100));
      }, 100);
    } else {
      if (processingTimerRef.current) clearInterval(processingTimerRef.current);
    }
    return () => { if (processingTimerRef.current) clearInterval(processingTimerRef.current); };
  }, [step]);

  const handlePayment = () => {
    setStep('processing');
    setErrorMessage('');
    setProcessingTime(0);

    setTimeout(() => {
      const isSuccessful = Math.random() > 0.2;
      if (isSuccessful) {
        setStep('success');
      } else {
        const errors = [
          "Transaction declined by your bank. Verify limits.",
          "Payment gateway timeout. Retrying node...",
          "UPI authentication failed.",
          "Session expired. Refreshing command."
        ];
        setErrorMessage(errors[Math.floor(Math.random() * errors.length)]);
        setStep('failure');
      }
    }, 2500);
  };

  const formatPrice = (price: number | undefined) => {
    return (price ?? 0).toLocaleString('en-IN');
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/90 backdrop-blur-xl animate-in fade-in duration-300">
      <div className="glass w-full max-w-xl rounded-[3rem] overflow-hidden shadow-[0_50px_100px_rgba(0,0,0,0.8)] border-white/10 animate-in zoom-in-95 duration-500">

        {step === 'details' && (
          <div className="p-10 md:p-12">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-3xl font-black text-white">Review Order</h2>
              <button onClick={onClose} className="h-12 w-12 glass border-white/10 rounded-full flex items-center justify-center text-white/40 hover:text-white transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-6 h-6">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>

            <div className="flex gap-6 mb-10 p-6 glass rounded-3xl border-white/10">
              <img src={hotel.image || 'https://images.unsplash.com/photo-1566073771259-6a8506099945?auto=format&fit=crop&q=80&w=800'} className="w-24 h-24 rounded-2xl object-cover border border-white/10" />
              <div className="flex flex-col justify-center">
                <h4 className="text-xl font-bold text-white">{hotel.name}</h4>
                <p className="text-sm text-white/40 font-bold uppercase tracking-widest mt-1">{hotel.location}</p>
                <div className="mt-2 text-indigo-400 font-black">₹{formatPrice(hotel.pricePerNight)} / night</div>
              </div>
            </div>

            <div className="space-y-4 mb-10 px-2">
              <div className="flex justify-between text-sm text-white/60 font-bold uppercase tracking-widest">
                <span>Total Charge</span>
                <span className="text-3xl font-black text-white">₹{formatPrice(hotel.totalPrice)}</span>
              </div>
            </div>

            <AgenticButton 
              onClick={() => setStep('guestInfo')}
              className="w-full py-6 text-sm"
            >
              Guest Checkout
            </AgenticButton>
          </div>
        )}

        {step === 'guestInfo' && (
          <div className="p-10 md:p-12">
            <div className="flex items-center gap-6 mb-10">
              <motion.button 
                whileHover={{ scale: 1.1, backgroundColor: 'rgba(255, 255, 255, 0.15)' }}
                onClick={() => setStep('details')} 
                className="h-12 w-12 bg-white/5 border border-white/10 rounded-full flex items-center justify-center text-[#A5B4FC] hover:text-white"
              >
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-5 h-5">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 19.5L8.25 12l7.5-7.5" />
                </svg>
              </motion.button>
              <h2 className="text-2xl font-black text-white">Guest Details</h2>
            </div>

            <div className="space-y-6 mb-10">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-white/40 tracking-widest">Full Name</label>
                <input 
                  type="text" 
                  value={guestInfo.name}
                  onChange={(e) => setGuestInfo({...guestInfo, name: e.target.value})}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-6 py-4 outline-none focus:ring-2 focus:ring-indigo-500/50 text-white"
                  placeholder="John Doe"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-white/40 tracking-widest">Email Address</label>
                <input 
                  type="email" 
                  value={guestInfo.email}
                  onChange={(e) => setGuestInfo({...guestInfo, email: e.target.value})}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-6 py-4 outline-none focus:ring-2 focus:ring-indigo-500/50 text-white"
                  placeholder="john@email.com"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-white/40 tracking-widest">Phone Number</label>
                <input 
                  type="tel" 
                  value={guestInfo.phone}
                  onChange={(e) => setGuestInfo({...guestInfo, phone: e.target.value})}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-6 py-4 outline-none focus:ring-2 focus:ring-indigo-500/50 text-white"
                  placeholder="+91 98765 43210"
                />
              </div>
            </div>

            <AgenticButton 
              disabled={!guestInfo.name || !guestInfo.email}
              onClick={() => setStep('payment')}
              className="w-full py-6 text-sm"
            >
              Next: Payment
            </AgenticButton>
          </div>
        )}

        {step === 'payment' && (
          <div className="p-10 md:p-12">
            <div className="flex items-center gap-6 mb-10">
              <motion.button 
                whileHover={{ scale: 1.1, backgroundColor: 'rgba(255, 255, 255, 0.15)' }}
                onClick={() => setStep('guestInfo')} 
                className="h-12 w-12 bg-white/5 border border-white/10 rounded-full flex items-center justify-center text-[#A5B4FC] hover:text-white"
              >
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-5 h-5">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 19.5L8.25 12l7.5-7.5" />
                </svg>
              </motion.button>
              <h2 className="text-2xl font-black text-white">Payment Method</h2>
            </div>

            <div className="space-y-4 mb-10">
              {[
                { id: 'upi', name: 'UPI (GPay, PhonePe, Paytm)', icon: '⚡' },
                { id: 'card', name: 'Credit / Debit Card', icon: '💳' }
              ].map((method) => (
                <label 
                  key={method.id}
                  className={`flex items-center gap-5 p-6 rounded-[1.5rem] border cursor-pointer transition-all duration-300 ${paymentMethod === method.id ? 'border-indigo-500 bg-indigo-500/10' : 'border-white/5 hover:bg-white/5'}`}
                >
                  <input type="radio" name="payment" className="hidden" checked={paymentMethod === method.id} onChange={() => setPaymentMethod(method.id)} />
                  <span className="text-2xl">{method.icon}</span>
                  <span className="flex-1 font-bold text-white/80">{method.name}</span>
                </label>
              ))}
            </div>

            <AgenticButton 
              onClick={handlePayment}
              className="w-full py-6 text-sm"
            >
              Confirm ₹{formatPrice(hotel.totalPrice)}
            </AgenticButton>
          </div>
        )}

        {step === 'processing' && (
          <div className="p-20 text-center space-y-8">
            <div className="relative h-24 w-24 mx-auto flex items-center justify-center">
              <div className="absolute inset-0 rounded-full border-4 border-white/5 border-t-indigo-500 animate-spin"></div>
              <span className="text-xs font-black text-white">{(processingTime / 10).toFixed(1)}s</span>
            </div>
            <h2 className="text-2xl font-black text-white">Encryption Protocol Active</h2>
            <p className="text-white/40 text-sm">Securing transaction for {guestInfo.email}</p>
          </div>
        )}

        {step === 'failure' && (
          <div className="p-16 text-center space-y-8 animate-in slide-in-from-top-4">
            <div className="h-20 w-20 bg-red-500/20 text-red-500 rounded-full mx-auto flex items-center justify-center shadow-[0_0_30px_rgba(239,68,68,0.3)]">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-10 h-10">
                <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </div>
            <div className="space-y-3">
              <h2 className="text-3xl font-black text-white">Transaction Fault</h2>
              <p className="text-white/50 font-medium px-4">{errorMessage}</p>
            </div>
            <AgenticButton 
              onClick={() => setStep('payment')} 
              className="w-full py-5 text-xs"
            >
              Retry Connection
            </AgenticButton>
          </div>
        )}

        {step === 'success' && (
          <div className="p-16 text-center space-y-8 animate-in zoom-in-95 duration-700">
            <div className="h-24 w-24 bg-indigo-500/20 text-indigo-400 rounded-full mx-auto flex items-center justify-center shadow-[0_0_50px_rgba(99,102,241,0.5)] animate-bounce">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={4} stroke="currentColor" className="w-12 h-12">
                <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" />
              </svg>
            </div>
            <div className="space-y-3">
              <h2 className="text-4xl font-black text-white">Mission Confirmed</h2>
              <p className="text-white/40 font-medium">Verified for {guestInfo.name}. Confirmation sent to {guestInfo.email}.</p>
            </div>
            <AgenticButton 
              onClick={onComplete} 
              className="w-full py-6 text-xs"
            >
              Return to Hub
            </AgenticButton>
          </div>
        )}
      </div>
    </div>
  );
};

