import { GoogleGenAI, Type } from "@google/genai";
import { Hotel } from "../types";

// Initialize with the mandatory API key pattern
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const HOTEL_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    hotels: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          name: { type: Type.STRING },
          rating: { type: Type.NUMBER },
          location: { type: Type.STRING },
          pricePerNight: { type: Type.NUMBER },
          totalPrice: { type: Type.NUMBER },
          image: { 
            type: Type.STRING, 
            description: "A DIRECT, valid, high-quality URL to a real photo of the hotel from official or reputable travel sites. MUST NOT be a generic placeholder or an AI prompt." 
          },
          bookingUrl: { 
            type: Type.STRING, 
            description: "The DIRECT official website booking page URL or a specific property page on a major platform like Booking.com/Agoda. MUST be a working link." 
          },
          description: { type: Type.STRING },
          whyPerfect: { type: Type.ARRAY, items: { type: Type.STRING } },
          aiAnalysis: {
            type: Type.OBJECT,
            properties: {
              positive: { type: Type.ARRAY, items: { type: Type.STRING } },
              concerns: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["positive", "concerns"]
          },
          inclusions: { type: Type.ARRAY, items: { type: Type.STRING } },
          comparisons: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                platform: { type: Type.STRING },
                price: { type: Type.NUMBER },
                isBest: { type: Type.BOOLEAN }
              },
              required: ["platform", "price"]
            }
          },
          tag: { type: Type.STRING }
        },
        required: [
          "id", "name", "rating", "location", "pricePerNight", "totalPrice", 
          "image", "bookingUrl", "description", "whyPerfect", "aiAnalysis", 
          "inclusions", "comparisons", "tag"
        ]
      }
    }
  },
  required: ["hotels"]
};

export async function searchHotels(userInput: string) {
  const prompt = `
    You are the Senior Operational Commander of TravelCrew AI.
    MISSION OBJECTIVE: Deploy your specialized agent crew to research and extract REAL data for the following request: "${userInput}".

    STRICT OPERATIONAL CONSTRAINTS:
    1. USE GOOGLE SEARCH GROUNDING: You MUST perform an active search to find ACTUAL hotels matching the request.
    2. DATA AUTHENTICITY: Do NOT use placeholders. 
       - Price: Must be the actual real-world price found in search results (usually in INR). It MUST NOT be 0.
       - Location: Extract the exact real-world address/neighborhood (e.g., "Candolim, North Goa" instead of "Location Pending").
       - Description: Provide a deep, factual summary based on the search results.
       - Images: Find a REAL, unique image URL for each specific hotel. Do NOT use the same image for multiple hotels.
       - Booking URL: Find the REAL, direct URL to the hotel's official site or its specific listing page.
    3. ANALYSIS: Synthesize review data from grounding sources (Google Reviews, TripAdvisor, MMT) to populate the aiAnalysis fields. Focus on cleanliness, food (Veg/Jain), and value.
    4. RETURN 3 OPTIONS:
       - "BEST MATCH": The top recommended property.
       - "BUDGET CHOICE": Most affordable valid option.
       - "PREMIUM UPGRADE": Highest luxury variant found.

    RESPONSE FORMAT: STRICT JSON only.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: HOTEL_SCHEMA,
        tools: [{ googleSearch: {} }]
      },
    });

    const responseText = response.text;
    if (!responseText) throw new Error("Mission Data Null");

    const json = JSON.parse(responseText);
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        title: chunk.web?.title || 'System Source',
        uri: chunk.web?.uri || ''
