export async function searchHotels(userInput: string) {
  const prompt = `
    ACT AS: Senior AI Travel Procurement Officer.
    MISSION: Research and extract REAL, VERIFIED data for: "${userInput}".

    STRICT OPERATIONAL DIRECTIVES:
    1. GROUNDING REQUIREMENT: Use Google Search to find ACTUAL hotels. 
    2. DATA INTEGRITY: 
       - LOCATION: Must be a real address or area. No "Location Pending".
       - PRICE: Must be a non-zero, realistic INR price.
       - IMAGES: You MUST find a real, unique image URL for each. If a direct hotel image is hard to find, use a specific Unsplash URL that matches the VIBE and CATEGORY of the hotel (e.g., luxury resort, business hotel).
       - BOOKING HUB: The 'bookingUrl' must be a real web address to the official site or a primary listing.
    3. EXTRACTION: From the search results of sites like Booking.com, TripAdvisor, and Expedia, synthesize EXACT details about food (Veg/Jain), room size, and proximity to stations/beaches.
    4. VARIETY: Provide 3 distinct options (Best Match, Budget, Luxury).

    DO NOT USE PLACEHOLDERS. ALL DATA MUST BE REAL.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: HOTEL_SCHEMA,
        tools: [{ googleSearch: {} }]
      },
    });

    const responseText = response.text;
    if (!responseText) throw new Error("Search node returned null data.");

    const json = JSON.parse(responseText);

    // Process sources to be more descriptive if possible
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        title: chunk.web?.title || 'Data Source',
        uri: chunk.web?.uri || ''
      })).filter((s: any) => s.uri) || [];

    return { ...json, sources };
  } catch (error: any) {
    console.error("Agent Search Error:", error);
    throw error;
  }
}

