  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { Hotel } from "../types";

// The API key is obtained exclusively from process.env.API_KEY as per guidelines.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const HOTEL_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    hotels: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          name: { type: Type.STRING },
          rating: { type: Type.NUMBER },
          location: { type: Type.STRING, description: "Detailed neighborhood and city. NO PLACEHOLDERS." },
          pricePerNight: { type: Type.NUMBER, description: "Current market rate in INR. MUST be > 0." },
          totalPrice: { type: Type.NUMBER, description: "Total for the duration. MUST be > 0." },
          image: { 
            type: Type.STRING, 
            description: "A UNIQUE, DIRECT, high-resolution URL to a real photo. Use actual deep links found in search. Every hotel MUST have a different image." 
          },
          bookingUrl: { 
            type: Type.STRING, 
            description: "The official website link for the hotel property." 
          },
          description: { type: Type.STRING, description: "Engaging 2-sentence summary." },
          whyPerfect: { type: Type.ARRAY, items: { type: Type.STRING }, description: "3 reasons why this matches Indian preferences." },
          aiAnalysis: {
            type: Type.OBJECT,
            properties: {
              positive: { type: Type.ARRAY, items: { type: Type.STRING } },
              concerns: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["positive", "concerns"]
          },
          inclusions: { type: Type.ARRAY, items: { type: Type.STRING } },
          comparisons: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                platform: { type: Type.STRING, description: "e.g., 'MakeMyTrip', 'Booking.com', 'Agoda'." },
                price: { type: Type.NUMBER },
                url: { type: Type.STRING, description: "The DEEP LINK to the specific hotel listing. If a direct deep link is not found, provide a platform-specific search URL for this hotel name. DO NOT provide generic homepages like 'booking.com'." },
                isBest: { type: Type.BOOLEAN }
              },
              required: ["platform", "price", "url"]
            }
          },
          tag: { type: Type.STRING }
        },
        required: [
          "id", "name", "rating", "location", "pricePerNight", "totalPrice", 
          "image", "bookingUrl", "description", "whyPerfect", "aiAnalysis", 
          "inclusions", "comparisons", "tag"
        ]
      }
    }
  },
  required: ["hotels"]
};

export async function searchHotels(userInput: string) {
  const prompt = `
    OPERATIONAL COMMAND: Deploy TravelCrew AI Agents to research and extract booking data for: "${userInput}".

    STRICT URL & DATA QUALITY PROTOCOLS:
    1. GROUNDING: Use Google Search to find REAL properties, LIVE prices, and working URLs.
    2. URL DEEP-LINKING: For 'comparisons', the 'url' MUST NOT be a generic homepage. It must be a specific URL that leads the user directly to this hotel's details on that platform (e.g. MakeMyTrip, Booking.com).
    3. RECOVERY: If a direct deep link is unavailable, construct a platform search URL: e.g., "https://www.booking.com/searchresults.html?ss=Hotel+Name+City".
    4. IMAGE DIVERSITY: Each hotel must have a unique, high-quality image URL.
    5. INDIAN CONTEXT: Focus on Indian users—prioritize MakeMyTrip prices where possible.

    MISSION: Return 3 highly-vetted options (Best, Value, Premium) as JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: HOTEL_SCHEMA,
        tools: [{ googleSearch: {} }]
      },
    });

    const responseText = response.text;
    if (!responseText) throw new Error("Agent search produced null results.");

    const json = JSON.parse(responseText);

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        title: chunk.web?.title || 'System Data Node',
        uri: chunk.web?.uri || ''
      })).filter((s: any) => s.uri) || [];

    return { ...json, sources };
  } catch (error: any) {
    console.error("Critical Mission Failure:", error);
    throw error;
  }
}

export async function chatWithCrew(userInput: string, context: Hotel[]) {
  const prompt = `
    You are the TravelCrew AI Hub. 
    Research results: ${JSON.stringify(context)}
    User Query: "${userInput}"

    Assist the user based on the researched data. If URLs are requested, explain which platform offers the best value.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    return "The communication link is experiencing high latency. Please retry the command.";
  }
}

import { GoogleGenAI, Type } from "@google/genai";
import { Hotel } from "../types";

/**
 * Utility to safely initialize the AI client.
 * This handles potential environment mismatches in Vercel/Browser environments.
 */
const getAIClient = () => {
  // Use a fallback check for process.env to prevent ReferenceErrors in some environments
  const apiKey = typeof process !== 'undefined' ? process.env.API_KEY : undefined;

  if (!apiKey) {
    console.error("ENVIRONMENT FAULT: process.env.API_KEY is undefined. Please add 'API_KEY' to your Vercel Project Settings -> Environment Variables.");
    throw new Error("API_KEY node not found in system environment. Connection to TravelCrew Hub failed.");
  }

  return new GoogleGenAI({ apiKey });
};

const HOTEL_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    hotels: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          name: { type: Type.STRING },
          rating: { type: Type.NUMBER },
          location: { type: Type.STRING, description: "Detailed neighborhood and city. NO PLACEHOLDERS." },
          pricePerNight: { type: Type.NUMBER, description: "Current market rate in INR. MUST be > 0." },
          totalPrice: { type: Type.NUMBER, description: "Total for the duration. MUST be > 0." },
          image: { 
            type: Type.STRING, 
            description: "A UNIQUE, DIRECT, high-resolution URL to a real photo. Use actual deep links found in search. Every hotel MUST have a different image." 
          },
          bookingUrl: { 
            type: Type.STRING, 
            description: "The official website link for the hotel property." 
          },
          description: { type: Type.STRING, description: "Engaging 2-sentence summary." },
          whyPerfect: { type: Type.ARRAY, items: { type: Type.STRING }, description: "3 reasons why this matches Indian preferences." },
          aiAnalysis: {
            type: Type.OBJECT,
            properties: {
              positive: { type: Type.ARRAY, items: { type: Type.STRING } },
              concerns: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["positive", "concerns"]
          },
          inclusions: { type: Type.ARRAY, items: { type: Type.STRING } },
          comparisons: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                platform: { type: Type.STRING, description: "e.g., 'MakeMyTrip', 'Booking.com', 'Agoda'." },
                price: { type: Type.NUMBER },
                url: { type: Type.STRING, description: "The DEEP LINK to the specific hotel listing. If a direct deep link is not found, provide a platform-specific search URL for this hotel name. DO NOT provide generic homepages like 'booking.com'." },
                isBest: { type: Type.BOOLEAN }
              },
              required: ["platform", "price", "url"]
            }
          },
          tag: { type: Type.STRING }
        },
        required: [
          "id", "name", "rating", "location", "pricePerNight", "totalPrice", 
          "image", "bookingUrl", "description", "whyPerfect", "aiAnalysis", 
          "inclusions", "comparisons", "tag"
        ]
      }
    }
  },
  required: ["hotels"]
};

export async function searchHotels(userInput: string) {
  const ai = getAIClient();
  const prompt = `
    OPERATIONAL COMMAND: Deploy TravelCrew AI Agents to research and extract booking data for: "${userInput}".

    STRICT URL & DATA QUALITY PROTOCOLS:
    1. GROUNDING: Use Google Search to find REAL properties, LIVE prices, and working URLs.
    2. URL DEEP-LINKING: For 'comparisons', the 'url' MUST NOT be a generic homepage. It must be a specific URL that leads the user directly to this hotel's details on that platform (e.g. MakeMyTrip, Booking.com).
    3. RECOVERY: If a direct deep link is unavailable, construct a platform search URL: e.g., "https://www.booking.com/searchresults.html?ss=Hotel+Name+City".
    4. IMAGE DIVERSITY: Each hotel must have a unique, high-quality image URL.
    5. INDIAN CONTEXT: Focus on Indian users—prioritize MakeMyTrip prices where possible.

    MISSION: Return 3 highly-vetted options (Best, Value, Premium) as JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: HOTEL_SCHEMA,
        tools: [{ googleSearch: {} }]
      },
    });

    const responseText = response.text;
    if (!responseText) throw new Error("Agent search produced null results.");

    const json = JSON.parse(responseText);

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        title: chunk.web?.title || 'System Data Node',
        uri: chunk.web?.uri || ''
      })).filter((s: any) => s.uri) || [];

    return { ...json, sources };
  } catch (error: any) {
    console.error("Critical Mission Failure:", error);
    throw error;
  }
}

export async function chatWithCrew(userInput: string, context: Hotel[]) {
  const ai = getAIClient();
  const prompt = `
    You are the TravelCrew AI Hub. 
    Research results: ${JSON.stringify(context)}
    User Query: "${userInput}"

    Assist the user based on the researched data. If URLs are requested, explain which platform offers the best value.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    return "The communication link is experiencing high latency. Please retry the command.";
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { motion } from 'framer-motion';
import Header from './components/Header';
import Footer from './components/Footer';
import AgentStatusPanel from './components/AgentStatusPanel';
import HotelCard from './components/HotelCard';
import ProfileView from './components/ProfileView';
import InfoView from './components/InfoView';
import AgenticButton from './components/AgenticButton';
import FloatingChat from './components/FloatingChat';
import { AppState, Hotel, AgentLog, ChatMessage, GroundingSource } from './types';
import { TRENDING_SEARCHES } from './constants';
import { searchHotels, chatWithCrew } from './services/geminiService';

const ESTIMATED_DEPLOY_TIME = 25; 

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.LANDING);
  const [query, setQuery] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [groundingSources, setGroundingSources] = useState<GroundingSource[]>([]);
  const [agentLogs, setAgentLogs] = useState<AgentLog[]>([
    { agent: 'Research Specialist', status: 'pending', message: 'Searching multiple platforms...' },
    { agent: 'Review Analyst', status: 'pending', message: 'Analyzing sentiment from 1000s of reviews...' },
    { agent: 'Price Specialist', status: 'pending', message: 'Comparing rates across 8+ sources...' },
    { agent: 'Amenity Checker', status: 'pending', message: 'Verifying facilities & dietary options...' },
    { agent: 'Booking Coordinator', status: 'pending', message: 'Ready for final confirmation...' }
  ]);
  const [results, setResults] = useState<Hotel[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [missionTimer, setMissionTimer] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  useEffect(() => {
    if (isLoading && (appState === AppState.SEARCHING)) {
      const start = Date.now();
      timerRef.current = window.setInterval(() => {
        setMissionTimer(Math.floor((Date.now() - start) / 1000));
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isLoading, appState]);

  const handleSearch = async (customQuery?: string) => {
    const activeQuery = customQuery || query;
    if (!activeQuery.trim()) return;

    setError(null);
    setAppState(AppState.SEARCHING);
    setIsLoading(true);
    setMissionTimer(0);
    setMessages([{ 
      id: Date.now().toString(), 
      role: 'user', 
      content: activeQuery, 
      timestamp: new Date().toLocaleTimeString() 
    }]);

    setAgentLogs(prev => prev.map(l => ({ ...l, status: 'pending' })));

    try {
      const stepTimer = window.setInterval(() => {
        setAgentLogs(prev => {
          const firstPending = prev.findIndex(l => l.status === 'pending');
          if (firstPending === -1) return prev;
          const newLogs = [...prev];
          newLogs[firstPending].status = 'working';
          if (firstPending > 0) newLogs[firstPending - 1].status = 'completed';
          return newLogs;
        });
      }, 2000);

      // Add a race against a timeout to prevent hanging UI
      const response = await Promise.race([
        searchHotels(activeQuery),
        new Promise((_, reject) => setTimeout(() => reject(new Error("Mission Timeout: Deployment taking longer than expected.")), 60000))
      ]) as any;

      clearInterval(stepTimer);

      setAgentLogs(prev => prev.map(l => ({ ...l, status: 'completed' })));

      const hotels = response.hotels || [];
      setResults(hotels);
      setGroundingSources(response.sources || []);

      const locationName = hotels[0]?.location ? hotels[0].location.split(',')[0] : 'your destination';

      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: `Crew mission success. Analyzed ${response.sources?.length || 0} datasets. Recommendations for ${locationName} mapped to your intent.`,
        timestamp: new Date().toLocaleTimeString()
      }]);

      setAppState(AppState.RESULTS);
    } catch (error: any) {
      console.error("handleSearch Error:", error);
      setError(error.message || "A deployment error occurred. Please try again.");
      setAppState(AppState.LANDING);
    } finally {
      setIsLoading(false);
    }
  };

  const handleChat = async () => {
    if (!chatInput.trim() || isLoading) return;
    const userMsg = chatInput;
    setChatInput('');
    setMessages(prev => [...prev, {
      id: Date.now().toString(),
      role: 'user',
      content: userMsg,
      timestamp: new Date().toLocaleTimeString()
    }]);

    setIsLoading(true);
    try {
      const response = await chatWithCrew(userMsg, results);
      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: response || "The crew is verifying details...",
        timestamp: new Date().toLocaleTimeString()
      }]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const onNavigate = (view: AppState) => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setError(null);
    setAppState(view);
  };

  const handleBook = (hotel: Hotel) => {
    if (hotel.bookingUrl) {
      window.open(hotel.bookingUrl, '_blank');
    } else {
      alert("Booking link unavailable for this property.");
    }
  };

  const renderContent = () => {
    const infoStates = [
      AppState.AGENTS_RESEARCH,
      AppState.AGENTS_REVIEWS,
      AppState.HOW_IT_WORKS,
      AppState.SECURITY_PRIVACY,
      AppState.SECURITY_PAYMENTS,
