            <p className="text-xl text-zinc-400 leading-relaxed font-medium">Node details incoming... Deploying framework components.</p>
            <AgenticButton onClick={() => onNavigate(AppState.LANDING)}>Return to Hub</AgenticButton>
          </div>
        );
